import{_ as d,C as c,o as i,c as p,a2 as a,b as o,w as t,a as s,E as r,a3 as l}from"./chunks/framework.B72_uj9U.js";const y=JSON.parse('{"title":"Pi — Core Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/pi-coding-agent/architecture.md","filePath":"research/agents/pi-coding-agent/architecture.md"}'),h={name:"research/agents/pi-coding-agent/architecture.md"};function g(m,e,u,f,b,k){const n=c("Mermaid");return i(),p("div",null,[e[2]||(e[2]=a(`<h1 id="pi-—-core-architecture" tabindex="-1">Pi — Core Architecture <a class="header-anchor" href="#pi-—-core-architecture" aria-label="Permalink to &quot;Pi — Core Architecture&quot;">​</a></h1><h2 id="high-level-design" tabindex="-1">High-Level Design <a class="header-anchor" href="#high-level-design" aria-label="Permalink to &quot;High-Level Design&quot;">​</a></h2><p>Pi&#39;s architecture is defined by its monorepo structure. Rather than a single monolithic application, Pi is composed of seven independently publishable npm packages, each with a clear responsibility boundary. The coding agent itself is just one package that composes the others. This separation means the LLM API, the agent runtime, and the terminal UI can each be used independently in other projects.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>pi-mono/</span></span>
<span class="line"><span>├── packages/</span></span>
<span class="line"><span>│   ├── ai/           @mariozechner/pi-ai          — Unified multi-provider LLM API</span></span>
<span class="line"><span>│   ├── agent/        @mariozechner/pi-agent-core   — Agent runtime, tool calling, state</span></span>
<span class="line"><span>│   ├── coding-agent/ @mariozechner/pi-coding-agent — The CLI application</span></span>
<span class="line"><span>│   ├── tui/          @mariozechner/pi-tui          — Terminal UI framework</span></span>
<span class="line"><span>│   ├── web-ui/       @mariozechner/pi-web-ui       — Web components for chat UIs</span></span>
<span class="line"><span>│   ├── mom/          @mariozechner/pi-mom          — Slack bot delegating to pi</span></span>
<span class="line"><span>│   └── pods/         @mariozechner/pi-pods         — CLI for managing vLLM on GPU pods</span></span>
<span class="line"><span>├── package.json          (workspace root)</span></span>
<span class="line"><span>└── tsconfig.json</span></span></code></pre></div><p>The dependency flow is strictly layered:</p>`,5)),(i(),o(l,null,{default:t(()=>[r(n,{id:"mermaid-13",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20AI%5B%22pi-ai%3Cbr%2F%3E(no%20internal%20deps)%22%5D%0A%20%20%20%20AC%5B%22pi-agent-core%3Cbr%2F%3E(depends%20on%20pi-ai)%22%5D%0A%20%20%20%20TUI%5B%22pi-tui%3Cbr%2F%3E(no%20internal%20deps%20%E2%80%94%20standalone%20UI%20framework)%22%5D%0A%20%20%20%20CA%5B%22pi-coding-agent%3Cbr%2F%3E(depends%20on%20pi-agent-core%20%2B%20pi-tui%20%2B%20pi-ai)%22%5D%0A%20%20%20%20UTILS%5B%22pi-mom%2C%20pi-web-ui%2C%20pi-pods%3Cbr%2F%3E(independent%20utilities)%22%5D%0A%20%20%20%20AI%20--%3E%20AC%0A%20%20%20%20AC%20--%3E%20CA%0A%20%20%20%20TUI%20--%3E%20CA%0A%20%20%20%20AI%20--%3E%20CA%0A%20%20%20%20CA%20--%3E%20UTILS%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=a('<h2 id="package-deep-dives" tabindex="-1">Package Deep Dives <a class="header-anchor" href="#package-deep-dives" aria-label="Permalink to &quot;Package Deep Dives&quot;">​</a></h2><h3 id="_1-pi-ai-—-unified-multi-provider-llm-api" tabindex="-1">1. pi-ai — Unified Multi-Provider LLM API <a class="header-anchor" href="#_1-pi-ai-—-unified-multi-provider-llm-api" aria-label="Permalink to &quot;1. pi-ai — Unified Multi-Provider LLM API&quot;">​</a></h3><p><code>pi-ai</code> is the foundation layer that abstracts away LLM provider differences. It supports four underlying API protocols:</p><table tabindex="0"><thead><tr><th>Protocol</th><th>Providers</th></tr></thead><tbody><tr><td>OpenAI Completions</td><td>OpenAI, Azure OpenAI, Groq, Cerebras, xAI, OpenRouter, Hugging Face, Kimi, MiniMax</td></tr><tr><td>OpenAI Responses</td><td>OpenAI (newer API)</td></tr><tr><td>Anthropic Messages</td><td>Anthropic, Bedrock (Anthropic models)</td></tr><tr><td>Google Generative AI</td><td>Google (Gemini models)</td></tr></tbody></table><p><strong>Key capabilities:</strong></p><ul><li><strong>Cross-provider context handoff</strong>: Convert conversation history between providers. This handles complex translations like Anthropic thinking traces → OpenAI system messages, signed content blobs that can&#39;t leave their provider, and different reasoning content field locations.</li><li><strong>Token and cost tracking</strong>: Best-effort tracking across providers with different reporting granularities.</li><li><strong>Provider quirk handling</strong>: Cerebras, xAI, and Mistral don&#39;t support the <code>store</code> field. Different providers use different <code>max_tokens</code> field names. Reasoning content lives in different response fields depending on the provider.</li><li><strong>Browser support</strong>: Some providers support CORS, so pi-ai works in browser contexts — enabling pi-web-ui.</li></ul><p>The abstraction is intentionally thin. Pi-ai doesn&#39;t try to normalize all provider behavior into a lowest-common-denominator API. Instead, it handles the sharp edges (field naming, unsupported parameters, content format translation) while preserving provider-specific capabilities.</p><h3 id="_2-pi-agent-core-—-agent-runtime" tabindex="-1">2. pi-agent-core — Agent Runtime <a class="header-anchor" href="#_2-pi-agent-core-—-agent-runtime" aria-label="Permalink to &quot;2. pi-agent-core — Agent Runtime&quot;">​</a></h3><p><code>pi-agent-core</code> provides the minimal scaffold for an agent loop:</p><ul><li><strong>Agent loop</strong>: The core cycle of receiving user input, calling the LLM, executing tool calls, feeding results back.</li><li><strong>Tool execution</strong>: Dispatching tool calls to registered handlers, collecting results, handling errors.</li><li><strong>State management</strong>: Tracking conversation history, tool call state, and session metadata.</li><li><strong>Event streaming</strong>: Emitting events (message received, tool call started, tool call completed, response streaming) that consumers can subscribe to.</li><li><strong>Validation</strong>: Ensuring tool call parameters meet schemas, handling malformed LLM responses.</li></ul><p>The design is deliberately minimal. There is no built-in concept of permissions, no planning layer, no sub-agent orchestration. These are concerns for the coding agent layer or extensions to handle.</p><h3 id="_3-pi-tui-—-terminal-ui-framework" tabindex="-1">3. pi-tui — Terminal UI Framework <a class="header-anchor" href="#_3-pi-tui-—-terminal-ui-framework" aria-label="Permalink to &quot;3. pi-tui — Terminal UI Framework&quot;">​</a></h3><p><code>pi-tui</code> is a custom terminal UI framework built from scratch — not based on Ink, blessed, or any existing terminal UI library. Key design choices:</p><ul><li><strong>Differential rendering</strong>: Only re-renders changed portions of the screen, eliminating flicker during streaming output. This is critical for a coding agent where LLM responses stream in token-by-token.</li><li><strong>Retained-mode UI</strong>: UI state is maintained in a tree of components. Updates modify the tree and trigger targeted re-renders rather than full-screen redraws.</li><li><strong>Synchronized output</strong>: Coordinates terminal output operations to prevent interleaving and visual corruption, especially important when multiple streams (agent output, user input, status indicators) are active simultaneously.</li></ul><p>The decision to build a custom TUI rather than use existing libraries reflects Pi&#39;s philosophy — existing solutions didn&#39;t meet the specific needs, and building from scratch meant full control over rendering behavior.</p><h3 id="_4-pi-coding-agent-—-the-cli" tabindex="-1">4. pi-coding-agent — The CLI <a class="header-anchor" href="#_4-pi-coding-agent-—-the-cli" aria-label="Permalink to &quot;4. pi-coding-agent — The CLI&quot;">​</a></h3><p>The coding agent itself composes the other packages and adds:</p><ul><li><strong>Default tool set</strong>: Four tools — <code>read</code>, <code>write</code>, <code>edit</code>, <code>bash</code> (see <a href="./tool-system.html">tool-system.md</a>)</li><li><strong>Extension system</strong>: TypeScript API for registering tools, commands, keyboard shortcuts, event handlers, UI components, and more (see <a href="./tool-system.html">tool-system.md</a>)</li><li><strong>Skills system</strong>: On-demand capability packages via SKILL.md files (see <a href="./tool-system.html">tool-system.md</a>)</li><li><strong>Context management</strong>: AGENTS.md, SYSTEM.md, compaction, prompt templates (see <a href="./context-management.html">context-management.md</a>)</li><li><strong>Session management</strong>: Tree-structured JSONL persistence with branching and forking (see <a href="./context-management.html">context-management.md</a>)</li><li><strong>Package management</strong>: Install/manage extensions and skills from npm or git</li><li><strong>Message queue</strong>: Steering and follow-up messages while agent works (see <a href="./agentic-loop.html">agentic-loop.md</a>)</li></ul><h2 id="the-four-modes-of-operation" tabindex="-1">The Four Modes of Operation <a class="header-anchor" href="#the-four-modes-of-operation" aria-label="Permalink to &quot;The Four Modes of Operation&quot;">​</a></h2><p>Pi runs in four distinct modes, each targeting a different use case:</p><h3 id="_1-interactive-mode-default" tabindex="-1">1. Interactive Mode (Default) <a class="header-anchor" href="#_1-interactive-mode-default" aria-label="Permalink to &quot;1. Interactive Mode (Default)&quot;">​</a></h3><p>The standard terminal experience. User types messages, sees streaming responses, can submit steering messages mid-generation. The full TUI is active with status lines, keyboard shortcuts, and extension-provided UI components.</p><h3 id="_2-print-json-mode" tabindex="-1">2. Print / JSON Mode <a class="header-anchor" href="#_2-print-json-mode" aria-label="Permalink to &quot;2. Print / JSON Mode&quot;">​</a></h3><p>Non-interactive output mode for scripting. Pi processes input and outputs results as plain text or structured JSON. Useful for CI pipelines, batch processing, and integration with other tools.</p><h3 id="_3-rpc-mode-stdin-stdout" tabindex="-1">3. RPC Mode (stdin/stdout) <a class="header-anchor" href="#_3-rpc-mode-stdin-stdout" aria-label="Permalink to &quot;3. RPC Mode (stdin/stdout)&quot;">​</a></h3><p>Pi acts as a JSON-RPC server over stdin/stdout. Other programs can drive pi programmatically — send messages, receive events, call tools. This is how pi-mom (the Slack bot) communicates with pi instances.</p><h3 id="_4-sdk-mode" tabindex="-1">4. SDK Mode <a class="header-anchor" href="#_4-sdk-mode" aria-label="Permalink to &quot;4. SDK Mode&quot;">​</a></h3><p>Direct programmatic access via the TypeScript API. Import pi-coding-agent as a library in your own application. Full access to the agent loop, tool system, and extension API without the CLI wrapper.</p>',28)),(i(),o(l,null,{default:t(()=>[r(n,{id:"mermaid-232",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20PCA%5B%22pi-coding-agent%22%5D%0A%20%20%20%20%20%20%20%20I%5B%22Interactive%3Cbr%2F%3E(TUI)%22%5D%0A%20%20%20%20%20%20%20%20P%5B%22Print%2FJSON%3Cbr%2F%3E(stdout)%22%5D%0A%20%20%20%20%20%20%20%20R%5B%22RPC%3Cbr%2F%3E(stdio)%22%5D%0A%20%20%20%20%20%20%20%20S%5B%22SDK%3Cbr%2F%3E(API)%22%5D%0A%20%20%20%20%20%20%20%20Core%5B%22Agent%20Core%20%2B%20Extensions%3Cbr%2F%3E4%20Tools%20%2B%20Ext%20Tools%22%5D%0A%20%20%20%20%20%20%20%20LLM%5B%22pi-ai%3Cbr%2F%3E(15%2B%20LLM%20Providers)%22%5D%0A%20%20%20%20%20%20%20%20I%20%26%20P%20%26%20R%20%26%20S%20--%3E%20Core%0A%20%20%20%20%20%20%20%20Core%20--%3E%20LLM%0A%20%20%20%20end%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[s(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=a('<h2 id="extension-skills-packages-architecture" tabindex="-1">Extension / Skills / Packages Architecture <a class="header-anchor" href="#extension-skills-packages-architecture" aria-label="Permalink to &quot;Extension / Skills / Packages Architecture&quot;">​</a></h2><p>Pi&#39;s extensibility forms a three-tier system:</p><h3 id="extensions-typescript-modules" tabindex="-1">Extensions (TypeScript Modules) <a class="header-anchor" href="#extensions-typescript-modules" aria-label="Permalink to &quot;Extensions (TypeScript Modules)&quot;">​</a></h3><p>The most powerful integration point. Extensions are TypeScript modules that hook into the agent lifecycle:</p><ul><li><strong>Tool registration</strong>: Add new tools or replace built-in tools entirely</li><li><strong>Command registration</strong>: Add slash commands accessible via <code>/command</code></li><li><strong>Event handlers</strong>: Subscribe to agent lifecycle events (message, tool call, response, etc.)</li><li><strong>UI components</strong>: Custom status lines, headers, footers, editors</li><li><strong>Keyboard shortcuts</strong>: Bind custom actions to key combinations</li><li><strong>Context manipulation</strong>: Inject messages, filter history, implement RAG</li></ul><h3 id="skills-capability-packages" tabindex="-1">Skills (Capability Packages) <a class="header-anchor" href="#skills-capability-packages" aria-label="Permalink to &quot;Skills (Capability Packages)&quot;">​</a></h3><p>Lighter-weight than extensions. A skill is a SKILL.md file that describes a capability:</p><ul><li>Stored in <code>~/.pi/agent/skills/</code> or project directories</li><li>Loaded on-demand via <code>/skill:name</code> or auto-loaded by the agent</li><li>Follows the Agent Skills standard (agentskills.io)</li><li>Provides progressive disclosure — capabilities are described only when needed</li></ul><h3 id="packages-distribution-format" tabindex="-1">Packages (Distribution Format) <a class="header-anchor" href="#packages-distribution-format" aria-label="Permalink to &quot;Packages (Distribution Format)&quot;">​</a></h3><p>Bundles of extensions, skills, prompts, and themes distributed via npm or git:</p><ul><li>Install: <code>pi install npm:@foo/pi-tools</code> or <code>pi install git:github.com/user/repo</code></li><li>npm keyword: <code>pi-package</code> for discoverability</li><li>Can contain any combination of extensions, skills, prompt templates, and themes</li></ul><p>This three-tier system means pi itself never needs to grow. New capabilities are added by the community as packages, keeping the core stable and predictable.</p>',12))])}const v=d(h,[["render",g]]);export{y as __pageData,v as default};
